sql:
SELECT risk_level, assessment_method
FROM risk_assessments
WHERE patient_id = 1;

SELECT patient_id, medication_name
FROM prescriptions
WHERE refills = 0;

external_knowledge:
Moderately at-risk: Indicates a medium risk level;
Recently: Refers to within the last 30 days;
Healthcare providers: Refers to doctors treating the patients.

sql:
SELECT COUNT(DISTINCT patient_id) 
FROM pregnancy_history 
WHERE gestational_diabetes = 1;

SELECT AVG(appointment_count)
FROM (
  SELECT doctor_id, COUNT(*) AS appointment_count
  FROM appointments
  GROUP BY doctor_id
);
